SELECT ia.TBL_INV_ADJUSTMENT_ID as tblInvAdjustmentId, ia.CMPY_CD as cmpyCd, ia.AGNT_CD as agntCd, ia.AGNT_NM as agntNm, ia.TBL_MTRL_M_ID as tblMtrlMId, ia.MTRL_CD as mtrlCd, ia.MTRL_NM as mtrlNm, ia.ADJUSTMENT_TYPE as adjustmentType, ia.BEFORE_QTY as beforeQty, ia.ADJUSTMENT_QTY as adjustmentQty, ia.AFTER_QTY as afterQty, ia.ADJUSTMENT_REASON as adjustmentReason, ia.ADJUSTMENT_DATE as adjustmentDate, ia.SAVE_TIME as saveTime, ia.SAVE_USER as saveUser, ia.UPDT_TIME as updtTime, ia.UPDT_USER as updtUser, ia.DELETED_YN as deletedYn FROM TBL_INV_ADJUSTMENT ia WHERE (ia.DELETED_YN IS NULL OR ia.DELETED_YN = 'N')
AND ia.CMPY_CD = #{cmpyCd}
AND ia.AGNT_CD = #{agntCd}
AND ia.MTRL_CD LIKE '%' + #{mtrlCd} + '%'
AND ia.MTRL_NM LIKE '%' + #{mtrlNm} + '%'
AND ia.ADJUSTMENT_TYPE = #{adjustmentType}
AND CONVERT(DATE, ia.ADJUSTMENT_DATE) >= #{dateFrom}
AND CONVERT(DATE, ia.ADJUSTMENT_DATE) <= #{dateTo}
ORDER BY ia.ADJUSTMENT_DATE DESC, ia.SAVE_TIME DESC OFFSET (#{pageNum} - 1) * #{pageSize} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM TBL_INV_ADJUSTMENT ia
WHERE (ia.DELETED_YN IS NULL OR ia.DELETED_YN = 'N')

    AND ia.CMPY_CD = #{cmpyCd}


    AND ia.AGNT_CD = #{agntCd}


    AND ia.MTRL_CD LIKE '%' + #{mtrlCd} + '%'


    AND ia.MTRL_NM LIKE '%' + #{mtrlNm} + '%'


    AND ia.ADJUSTMENT_TYPE = #{adjustmentType}


    AND CONVERT(DATE, ia.ADJUSTMENT_DATE) >= #{dateFrom}


    AND CONVERT(DATE, ia.ADJUSTMENT_DATE) <= #{dateTo}

SELECT ip.TBL_INV_PRODUCT_ID as tblInvProductId, ip.CMPY_CD as cmpyCd, ip.AGNT_CD as agntCd, ip.AGNT_NM as agntNm, ip.TBL_MTRL_M_ID as tblMtrlMId, ip.MTRL_CD as mtrlCd, ip.MTRL_NM as mtrlNm, ip.CURRENT_QTY as currentQty, ip.SAVE_TIME as saveTime, ip.SAVE_USER as saveUser, ip.UPDT_TIME as updtTime, ip.UPDT_USER as updtUser FROM TBL_INV_PRODUCT ip WHERE 1=1
AND ip.CMPY_CD = #{cmpyCd}
AND ip.AGNT_CD = #{agntCd}
AND ip.MTRL_CD LIKE '%' + #{mtrlCd} + '%'
AND ip.MTRL_NM LIKE '%' + #{mtrlNm} + '%'
ORDER BY ip.UPDT_TIME DESC, ip.SAVE_TIME DESC OFFSET (#{pageNum} - 1) * #{pageSize} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*) FROM TBL_INV_PRODUCT ip WHERE 1=1
AND ip.CMPY_CD = #{cmpyCd}
AND ip.AGNT_CD = #{agntCd}
AND ip.MTRL_CD LIKE '%' + #{mtrlCd} + '%'
AND ip.MTRL_NM LIKE '%' + #{mtrlNm} + '%'

